(function(w){"use strict";const ID="day-of-week";function p(v){if(!/^\d{4}-\d{2}-\d{2}$/.test(v||""))return null;const a=v.split("-").map(Number),d=new Date(a[0],a[1]-1,a[2]);return d.getFullYear()===a[0]&&d.getMonth()===a[1]-1&&d.getDate()===a[2]?d:null}function compute(x){const d=p(x.date);if(!d)return{error:"날짜를 올바르게 입력해 주세요."};const names=['일요일','월요일','화요일','수요일','목요일','금요일','토요일'];return{day:d.getDay(),name:names[d.getDay()]}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>날짜</label><input class="hm-calc-input" type="date"></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">요일 확인</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");input.value=api.localDateString();go.addEventListener("click",()=>{const r=compute({date:input.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("요일",r.name));});}
w.HM_CALC.register(ID,{compute,render});})(window);
